import Foundation

struct Point: Comparable {
    let x: Double
    let y: Double

    var distanceFromOrigin: Double {
        hypot(x, y)
    }

    static func < (lhs: Point, rhs: Point) -> Bool {
        lhs.distanceFromOrigin < rhs.distanceFromOrigin
    }
}

